class Solution:
    def isMatch(self, s: str, p: str) -> bool:
        m, n = len(s), len(p)

        # dp[i][j] will be true if s[0...i-1] matches p[0...j-1]
        dp = [[False] * (n + 1) for _ in range(m + 1)]

        # Base case: empty string matches empty pattern
        dp[0][0] = True

        # Handle patterns like a*, a*b*, etc. matching empty string
        for j in range(1, n + 1):
            if p[j-1] == '*':
                dp[0][j] = dp[0][j-2] # Zero occurrences of p[j-2]

        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if p[j-1] == s[i-1] or p[j-1] == '.':
                    dp[i][j] = dp[i-1][j-1]
                elif p[j-1] == '*':
                    # Case 1: Zero occurrences of p[j-2]
                    # e.g., s = "a", p = "ab*" -> dp[1][3] = dp[1][1] (match "a" with "a")
                    dp[i][j] = dp[i][j-2]

                    # Case 2: One or more occurrences of p[j-2]
                    # This is only possible if p[j-2] matches s[i-1] or p[j-2] is '.'
                    if p[j-2] == s[i-1] or p[j-2] == '.':
                        # If p[j-2] matches s[i-1], then s[0...i-1] matches p[0...j-1]
                        # if s[0...i-2] matches p[0...j-1] (one more char matched by '*')
                        dp[i][j] = dp[i][j] or dp[i-1][j]

        return dp[m][n]

