import java.util.HashSet;
import java.util.Set;

class Solution {
    public boolean containsDuplicate(int[] nums) {
        Set<Integer> seen = new HashSet<>();
        for (int num : nums) {
            // 如果集合中已经包含当前数字，说明找到了重复项
            if (seen.contains(num)) {
                return true;
            }
            // 否则，将当前数字添加到集合中
            seen.add(num);
        }
        // 遍历完所有数字都没有找到重复项
        return false;
    }
}
