class Solution {
    public boolean isAnagram(String s, String t) {
        if (s.length() != t.length()) {
            return false;
        }

        // Using an array of size 26 for lowercase English letters
        int[] charCounts = new int[26];

        // Increment counts for characters in string s
        for (char c : s.toCharArray()) {
            charCounts[c - 'a']++;
        }

        // Decrement counts for characters in string t
        for (char c : t.toCharArray()) {
            charCounts[c - 'a']--;
        }

        // Check if all counts are zero
        // If they are, it means both strings had the same characters with the same frequencies
        for (int count : charCounts) {
            if (count != 0) {
                return false;
            }
        }

        return true;
    }
}
